 55→// Animated number hook for smooth credit transitions
 56→const useAnimatedNumber = (value: number, duration = 600) => {
 57→  const [display, setDisplay] = useState(value);
 58→  const prevValue = useRef(value);
 59→  useEffect(() => {
 60→    if (prevValue.current === value) return;
 61→    const start = prevValue.current;
 62→    const diff = value - start;
 63→    const startTime = performance.now();
 64→    const animate = (now: number) => {
 65→      const progress = Math.min((now - startTime) / duration, 1);
 66→      const eased = 1 - Math.pow(1 - progress, 3);
 67→      setDisplay(Math.round(start + diff * eased));
 68→      if (progress < 1) requestAnimationFrame(animate);
 69→    };
 70→    requestAnimationFrame(animate);
 71→    prevValue.current = value;
 72→  }, [value, duration]);
 73→  return display;
 74→};
